<template>
  <v-app>
    <v-navigation-drawer app permanent>
      <v-toolbar fixed flat>
        <v-list>
          <v-list-tile>
            <v-list-tile-title class="title">MPC Alpha</v-list-tile-title>
          </v-list-tile>
        </v-list>
      </v-toolbar>
      <v-container style="margin-top: 52px; overflow-y: auto;" app grid-list-xs fluid>
        <v-layout v-for="item in items" :key="item.id" row wrap>
          <v-flex xs12>
            <v-card :color="item.color" class="white--text">
              <v-card-title primary-title>
                <div>
                  <div class="headline">{{item.title}}</div>
                  <div
                    class="caption grey--text text--lighten-3"
                  >Acur. {{item.accuracy}} &#9672; {{item.nodes}} nós &#9672; {{item.layers}} camadas</div>
                  <div class="body-1">{{item.desc}}</div>
                </div>
              </v-card-title>
              <v-card-actions>
                <v-btn
                  :disabled="isLoading"
                  :loading="isLoading"
                  v-if="item.adicional !== undefined"
                  @click.native="showInformation(item.adicional)"
                  flat
                  dark
                >
                  <v-icon style="margin-right:8px">info</v-icon>Info
                </v-btn>
                <v-btn
                  :disabled="isLoading"
                  :loading="isLoading"
                  @click="loadNetwork(item)"
                  flat
                  dark
                >
                  <v-icon style="margin-right:8px">play_arrow</v-icon>Play
                </v-btn>
              </v-card-actions>
            </v-card>
          </v-flex>
        </v-layout>
      </v-container>
    </v-navigation-drawer>
    <v-content>
      <network-renderer
        :network="network"
        v-on:nodeMouseOver="onNodeMouseOver"
        v-on:nodeMouseClick="onNodeMouseClick"
        ref="renderer"
      ></network-renderer>
      <div class="playback-controls">
        <v-layout row wrap>
          <v-btn
            fab
            small
            :disabled="!controlsEnabled"
            :color="currentColor"
            @click.stop="play"
            :loading="isLoading"
            dark
          >
            <v-icon>{{ this.isPlaying ? 'pause' : 'play_arrow'}}</v-icon>
          </v-btn>
          <v-slider
            class="playback"
            :disabled="!controlsEnabled"
            :color="currentColor"
            :readonly="isPlaying"
            v-model="userCurrentIterationControl"
            :max="iterations.length"
            :thumb-label="isPlaying ? 'always' : ''"
          ></v-slider>
          <v-btn
            :disabled="!controlsEnabled || isPlaying"
            fab
            small
            :color="currentColor"
            dark
            @click.native.stop="nextIteration"
            :loading="isLoading"
          >
            <v-icon>chevron_right</v-icon>
          </v-btn>
        </v-layout>
      </div>

      <v-dialog v-model="dialog" width="500">
        <v-card>
          <v-card-title class="headline grey lighten-2" primary-title>MPC-Alpha</v-card-title>

          <v-card-text>
            Para visualizar o processo de classificação da versão atual da Competição de Partículas Multicamada, selecione uma rede no menu ao lado clicando na opção "play" e em seguida, clique em
            <b>reproduzir</b>, no canto inferior.
            <br>
            <br>As seguintes redes estão disponíveis:
            <br>
            <v-list dense two-line>
              <v-list-tile @click="navigateTo('http://proj.ise.bgu.ac.il/sns/students.html')">
                <v-list-tile-content>
                  <v-list-tile-title class="title">Students’ Cooperation Social Network</v-list-tile-title>
                  <v-list-tile-sub-title>185 vértices | 3 camadas | Multiplex | 51 comunidades (chute)</v-list-tile-sub-title>
                </v-list-tile-content>
              </v-list-tile>
              <v-list-tile @click="navigateTo('https://arxiv.org/abs/1408.2925')">
                <v-list-tile-content>
                  <v-list-tile-title class="title">Pierre Auger Collaboration</v-list-tile-title>
                  <v-list-tile-sub-title>514 vértices | 16 camadas | Multiplex | 30 comunidades (chute)</v-list-tile-sub-title>
                </v-list-tile-content>
              </v-list-tile>
              <v-list-tile @click.stop>
                <v-list-tile-content>
                  <v-list-tile-title class="title">Rede artificial #1</v-list-tile-title>
                  <v-list-tile-sub-title>200 vértices | 4 camadas | Multiplex | 4 - 10 comunidades</v-list-tile-sub-title>
                </v-list-tile-content>
              </v-list-tile>
              <v-list-tile @click.stop>
                <v-list-tile-content>
                  <v-list-tile-title class="title">Rede artificial #2</v-list-tile-title>
                  <v-list-tile-sub-title>200 vértices | 4 camadas | Multiplex | 4 - 10 comunidades</v-list-tile-sub-title>
                </v-list-tile-content>
              </v-list-tile>
            </v-list>
            <b>O uso do Chrome é recomendado.</b>
          </v-card-text>

          <v-divider></v-divider>

          <v-card-actions>
            <v-spacer></v-spacer>
            <v-btn color="primary" flat @click="dialog = false">OK</v-btn>
          </v-card-actions>
        </v-card>
      </v-dialog>
      <v-dialog v-model="info" width="500">
        <v-card>
          <v-card-title class="headline grey lighten-2" primary-title>MPC-Alpha: informação</v-card-title>

          <v-card-text v-html="info_text"></v-card-text>

          <v-divider></v-divider>

          <v-card-actions>
            <v-spacer></v-spacer>
            <v-btn color="primary" flat @click="info = false">OK</v-btn>
          </v-card-actions>
        </v-card>
      </v-dialog>
    </v-content>
  </v-app>
</template>
<script>
import NetworkRenderer from '../components/NetworkRenderer';
import axios from 'axios';
import _ from 'underscore';

export default {
  name: 'mpc-alpha',
  data: function () {
    return {
      network: null,
      iterations: [],
      currentIteration: 0,
      userCurrentIterationControl: 0,
      requiresFullUpdate: false,
      isPlaying: false,
      playingInterval: null,
      currentColor: 'black',
      isLoading: false,
      dialog: true,
      info: false,
      info_text: '',
      items: [{
        id: 8,
        title: "Pierre Auger Collaboration",
        desc: 'Execução com K = 30. Rede multiplex de colaboração entre autores, considerando submissões entre 2010 e 2012. Cada camada representa uma área de atuação.',
        adicional: `The multiplex consists of layers corresponding to different working tasks within the Pierre Auger Collaboration. We considered all submissions between 2010 and 2012 and assigned each report to 16 layers according to its keywords and its content, with manual disambiguation to avoid spurious results from an automated process.<br>
The multiplex network used in the paper makes use of 16 layers corresponding to:<br>
◈ Neutrinos<br>
◈ Detector<br>
◈ Enhancements<br>
◈ Anisotropy<br>
◈ Point-source<br>
◈ Mass-composition<br>
◈ Horizontal<br>
◈ Hybrid-reconstruction<br>
◈ Spectrum<br>
◈ Photons<br>
◈ Atmospheric<br>
◈ SD-reconstruction<br>
◈ Hadronic-interactions<br>
◈ Exotics<br>
◈ Magnetic<br>
◈ Astrophysical-scenarios`,
        file: '/mpc-playbacks/coauthorship_30.json',
        accuracy: '?',
        layers: 16,
        nodes: 514,
        color: 'black darken-2'
      }, {
        id: 9,
        title: "Students’ Cooperation Social Network",
        desc: '185 vértices em 3 camadas, com 51 partículas na rede. Não há tratamento de componentes.',
        file: '/mpc-playbacks/students.json',
        nodes: 185,
        layers: 3,
        adicional: `Students’ Cooperation Social Network was constructed from the data collected during a “Computer and Network Security” course; a mandatory course at Ben-Gurion University. The social network contains data collected from 185 participating students from two different departments. The course’s social network was created by analyzing the implicit and explicit cooperation among the students while doing their homework assignments. The students’ cooperation graph contained 185 nodes and 360 links and 3 types of links. `,
        accuracy: '?',
        color: 'red darken-2'
      },
      {
        id: 1,
        title: "Artificial #2",
        desc: '80 vértices em 4 comunidades contendo apenas uma conexão entre cada comunidade. Acurácia de 100%.',
        file: '/mpc-playbacks/art2_4com_low.json',
        accuracy: '100%',
        nodes: 80,
        layers: 4,
        color: 'teal darken-2'
      },
      {
        id: 2,
        title: "Artificial #2",
        desc: '80 vértices em 4 comunidades. Acurácia de 100%',
        nodes: 80,
        layers: 4,
        file: '/mpc-playbacks/art2_4com_dense.json',
        accuracy: '100%',
        color: 'teal darken-2'
      },
      {
        id: 3,
        title: "Artificial #2",
        desc: '40 vértices em 4 comunidades, bem conectado entre as comunidades. Acurácia de 100%',
        file: '/mpc-playbacks/art2_4com_dense.json',
        accuracy: '100%',
        color: 'teal darken-2',
        nodes: 40,
        layers: 4,
      }, {
        id: 4,
        title: "Artificial #2 (c/ falha)",
        desc: '100 vértices em 10 comunidades, altamente conectado entre as comunidades. Com fenômeno de falha. Acurácia de 90%',
        file: '/mpc-playbacks/art2_10com_high.json',
        accuracy: '90%',
        nodes: 100,
        layers: 4,
        color: 'orange darken-2'
      }, {
        id: 5,
        title: "Artificial #2 (s/ falha)",
        desc: '100 vértices em 10 comunidades, altamente conectado entre as comunidades. Acurácia de 100%',
        file: '/mpc-playbacks/art2_10com_high_no_failure.json',
        accuracy: '100%',
        nodes: 100,
        layers: 4,
        color: 'orange darken-2'

      }, {
        id: 6,
        title: "Artificial #1 (90%)",
        desc: '100 vértices em 4 comunidades, 90% de conexões internas. Acurácia de 100%',
        file: '/mpc-playbacks/art1_4_90.json',
        accuracy: '100%',
        nodes: 100,
        layers: 4,
        color: 'grey darken-2'
      }, {
        id: 10,
        title: "Artificial #1 (90%)",
        desc: '200 vértices em 4 comunidades, 10 vizinhos, c/ 90% de conexões internas. Acurácia de 100%',
        file: '/mpc-playbacks/art1_4_bigger_90.json',
        accuracy: '100%',
        nodes: 200,
        layers: 4,
        color: 'grey darken-2'
      }, {
        id: 7,
        title: "Artificial #1 (70%)",
        desc: '200 vértices em 4 comunidades, 10 vizinhos, 70% de conexões internas. Acurácia de 99,5%',
        file: '/mpc-playbacks/art1_4_70.json',
        accuracy: '99,5%',
        nodes: 200,
        layers: 4,
        color: 'grey darken-2'
      }, {
        id: 11,
        title: "Artificial #1 (50%)",
        desc: '200 vértices em 4 comunidades, 10 vizinhos, 50% de conexões internas. Acurácia de 95%',
        file: '/mpc-playbacks/art1_4_50.json',
        accuracy: '95%',
        nodes: 200,
        layers: 4,
        color: 'grey darken-2'
      },
      ]
    };
  },
  watch: {
    userCurrentIterationControl: _.debounce(function (newValue) {
      this.currentIteration = newValue;
    }, 200),
    currentIteration: function (newValue, oldValue) {
      const diff = newValue - oldValue;
      if (diff > 1 || diff < 0) {
        this.fullUpdate();
      } else {
        this.updateIteration(newValue);
      }
      this.userCurrentIterationControl = newValue;
    }
  },
  computed: {
    controlsEnabled: function () { return this.network !== null && this.iterations.length > 0; }
  },
  methods: {
    navigateTo(url) {
      window.open(url, '_blank');
    },
    showInformation(text) {
      this.info = true;
      this.info_text = text;
    },
    loadNetwork: function (item) {
      this.isLoading = true;
      this.reset();
      axios.get(item.file).then(response => {
        this.currentColor = item.color;
        console.log(response);
        const file = response.data;
        this.network = file.network;
        this.iterations = file.iterations;
        this.currentIteration = 0;
        this.isLoading = false;
      }).catch(err => {
        console.log(err);
        alert("Não foi possível carregar esse recurso: " + err.message);
        this.isLoading = false;
      });
    },
    reset: function () {
      clearInterval(this.playingInterval);
      this.playingInterval = null;
      this.isPlaying = false;
      this.iterations = [];
      this.network = null;
      this.currentIteration = 0;
      this.userCurrentIterationControl = 0;
    },
    play: function () {
      if (!this.isPlaying) {
        this.playingInterval = setInterval(() => {
          this.currentIteration++;
        }, 10);
      } else {
        clearInterval(this.playingInterval);
        this.playingInterval = null;
      }
      this.isPlaying = !this.isPlaying;
      this.currentIteration++;
    },
    nextIteration: function () {
      this.currentIteration++;
    },
    fullUpdate: function () {
      const remaining = {};
      this.network.layerNodes.map(layerNode => {
        remaining[layerNode.id] = true;
      });

      const update = {};
      for (let i = this.currentIteration; i > 0; i--) {
        Object.keys(remaining).map(layerNodeId => {
          const color = this.iterations[i][layerNodeId];
          if (color !== undefined) {
            update[layerNodeId] = color;
            delete remaining[layerNodeId];
          }
        });
      }

      this.network.layerNodes.map(layerNode => {
        layerNode.color = update[layerNode.id];
      });
      this.$refs.renderer.refreshNodes();
    },
    updateIteration: function (index) {
      const particleLocations = this.iterations[index]["particles"];


      this.network.layerNodes.map(layerNode => {
        const layerNodeUpdate = this.iterations[index][layerNode.id];
        if (layerNodeUpdate !== undefined &&
          layerNode.color != layerNodeUpdate) {
          layerNode.color = layerNodeUpdate;
        }
        if (particleLocations[layerNode.id] !== undefined) {
          layerNode.opacity = 1;
          layerNode.color = particleLocations[layerNode.id];
        } else {
          layerNode.opacity = 0.5;
        }
      });

      this.$refs.renderer.refreshNodes();
    },

    onNodeMouseOver: function (data) { },
    onNodeMouseClick: function (data) { }
  },
  components: {
    'network-renderer': NetworkRenderer
  }
}
</script>
<style scoped>
.img-network {
  height: 100px;
  width: 100%;
}

.playback-controls {
  position: absolute;
  bottom: 10px;
  width: 100%;
}
.playback {
  margin-left: 10px;
}
</style>

